  1	import * as React from "react";
  2	import TagsInput from "react-tagsinput";
  3	
  4	import { K8sResourceCommon } from "@openshift-console/dynamic-plugin-sdk";
  5	import { Label as PFLabel, Stack, StackItem } from "@patternfly/react-core";
  6	
  7	import { isLabelValid, labelsArrayToObject, labelsToArray } from "./utils";
  8	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
  9	import TabModal from "../TabModal/TabModal";
 10	import "./labels-modal.css";
 11	
 12	type LabelsModalProps = {
 13	  isOpen: boolean;
 14	  obj: K8sResourceCommon;
 15	  labelClassName?: string;
 16	  onLabelsSubmit: (labels: {
 17	    [key: string]: string;
 18	  }) => Promise<void | K8sResourceCommon>;
 19	  onClose: () => void;
 20	};
 21	
 22	export const LabelsModal: React.FC<LabelsModalProps> = React.memo(
 23	  ({ isOpen, obj, labelClassName, onLabelsSubmit, onClose }) => {
 24	    const { t } = useNodeHealthCheckTranslation();
 25	    const [inputValue, setInputValue] = React.useState("");
 26	    const [isInputValid, setIsInputValid] = React.useState(true);
 27	    const [labels, setLabels] = React.useState<string[]>(
 28	      labelsToArray(obj?.metadata?.labels || {})
 29	    );
 30	
 31	    const onInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
 32	      const value = e.target.value;
 33	
 34	      if (value === "") {
 35	        setInputValue(value);
 36	        setIsInputValid(true);
 37	        return;
 38	      }
 39	      setInputValue(value);
 40	      setIsInputValid(isLabelValid(value));
 41	    };
 42	
 43	    const handleLabelsChange = (newLabels: string[], changed: string[]) => {
 44	      const newLabel = changed[0];
 45	      if (!isLabelValid(newLabel)) {
 46	        setIsInputValid(false);
 47	        return;
 48	      }
 49	
 50	      // duplicate labels
 51	      if (newLabels.filter((l) => l === newLabel).length > 1) {
 52	        setIsInputValid(false);
 53	        return;
 54	      }
 55	
 56	      // if key exists, overwrite value
 57	      if (
 58	        newLabels.filter((l) => l.split("=")[0] === newLabel.split("=")[0])
 59	          .length > 1
 60	      ) {
 61	        const filteredLabels = newLabels.filter(
 62	          (l) => l.split("=")[0] !== newLabel.split("=")[0]
 63	        );
 64	        setLabels([...filteredLabels, newLabel]);
 65	        setInputValue("");
 66	        return;
 67	      }
 68	
 69	      setLabels(newLabels);
 70	      setInputValue("");
 71	    };
 72	
 73	    const renderTag = ({ tag, key, onRemove, getTagDisplayValue }) => {
 74	      return (
 75	        <PFLabel
 76	          className={"tag-item-content".concat(labelClassName || "")}
 77	          key={key}
 78	          onClose={() => onRemove(key)}
 79	          textMaxWidth="16ch"
 80	        >
 81	          {getTagDisplayValue(tag)}
 82	        </PFLabel>
 83	      );
 84	    };
 85	
 86	    // reset labels when modal is closed
 87	    React.useEffect(() => {
 88	      if (obj?.metadata?.labels) {
 89	        setLabels(labelsToArray(obj?.metadata?.labels || {}));
 90	      }
 91	      // eslint-disable-next-line react-hooks/exhaustive-deps
 92	    }, [isOpen]);
 93	
 94	    const inputProps = {
 95	      autoFocus: true,
 96	      className: "input".concat(isInputValid ? "" : " invalid-tag"),
 97	      onChange: onInputChange,
 98	      placeholder: labels.length === 0 ? "app=frontend" : "",
 99	      spellCheck: "false",
100	      value: inputValue,
101	      id: "tags-input",
102	      ["data-test"]: "tags-input",
103	    };
104	
105	    // Keys that add tags: Enter
106	    const addKeys = [13];
107	    // Backspace deletes tags, but not if there is text being edited in the input field
108	    const removeKeys = inputValue.length ? [] : [8];
109	
110	    return (
111	      <TabModal
112	        obj={obj}
113	        headerText={t("Edit labels")}
114	        onSubmit={() => onLabelsSubmit(labelsArrayToObject(labels))}
115	        isOpen={isOpen}
116	        onClose={onClose}
117	      >
118	        <Stack hasGutter>
119	          <StackItem>
120	            {t(
121	              "Labels help you organize and select resources. Adding labels below will let you query for objects that have similar, overlapping or dissimilar labels."
122	            )}
123	          </StackItem>
124	          <StackItem>
125	            <div className="nhc-details--labels__input pf-c-form-control">
126	              <tags-input>
127	                <TagsInput
128	                  className="tags"
129	                  value={labels}
130	                  addKeys={addKeys}
131	                  removeKeys={removeKeys}
132	                  inputProps={inputProps}
133	                  renderTag={renderTag}
134	                  onChange={handleLabelsChange}
135	                  addOnBlur
136	                />
137	              </tags-input>
138	            </div>
139	          </StackItem>
140	        </Stack>
141	      </TabModal>
142	    );
143	  }
144	);
145	
146	// console is declaring a new html element for some reason, we have to copy it for css reasons.
147	declare global {
148	  // eslint-disable-next-line @typescript-eslint/no-namespace
149	  namespace JSX {
150	    interface IntrinsicElements {
151	      "tags-input": React.DetailedHTMLProps<
152	        React.HTMLAttributes<HTMLElement>,
153	        HTMLElement
154	      >;
155	    }
156	  }
157	}

